import React, { useRef, useState } from 'react';
import { Loader2, CheckCircle2, FileText, Upload, AlertTriangle, FileBarChart } from 'lucide-react';

interface ContentInputProps {
  lessonContent: string;
  setLessonContent: (val: string) => void;
  distributionContent: string;
  setDistributionContent: (val: string) => void;
}

// Khai báo thư viện ngoại
declare const mammoth: any;
declare const pdfjsLib: any;

const ContentInput: React.FC<ContentInputProps> = ({ 
  lessonContent, 
  setLessonContent,
  distributionContent,
  setDistributionContent
}) => {
  const lessonInputRef = useRef<HTMLInputElement>(null);
  const distInputRef = useRef<HTMLInputElement>(null);

  const [processingLesson, setProcessingLesson] = useState(false);
  const [processingDist, setProcessingDist] = useState(false);

  const [lessonFileName, setLessonFileName] = useState<string | null>(null);
  const [distFileName, setDistFileName] = useState<string | null>(null);

  const processFile = async (file: File, isLesson: boolean) => {
    const setProcessing = isLesson ? setProcessingLesson : setProcessingDist;
    const setContent = isLesson ? setLessonContent : setDistributionContent;
    const setFileName = isLesson ? setLessonFileName : setDistFileName;

    setProcessing(true);
    setFileName(file.name);

    try {
      const arrayBuffer = await file.arrayBuffer();
      let text = "";

      if (file.type === "application/pdf" || file.name.endsWith(".pdf")) {
        text = await extractTextFromPDF(arrayBuffer);
      } else if (
        file.type === "application/vnd.openxmlformats-officedocument.wordprocessingml.document" || 
        file.name.endsWith(".docx")
      ) {
        text = await extractTextFromDOCX(arrayBuffer);
      } else {
        alert("Định dạng file không được hỗ trợ. Vui lòng chọn PDF hoặc DOCX.");
        setFileName(null);
        setProcessing(false);
        return;
      }

      if (!text.trim()) {
        alert("Không thể đọc được nội dung văn bản từ file này. Có thể file chứa ảnh scan?");
        setFileName(null);
      } else {
        setContent(text);
      }

    } catch (error) {
      console.error("Error processing file:", error);
      alert("Có lỗi xảy ra khi đọc file.");
      setFileName(null);
    } finally {
      setProcessing(false);
    }
  };

  const extractTextFromDOCX = async (arrayBuffer: ArrayBuffer): Promise<string> => {
    if (typeof mammoth === 'undefined') return "";
    const result = await mammoth.extractRawText({ arrayBuffer });
    return result.value;
  };

  const extractTextFromPDF = async (arrayBuffer: ArrayBuffer): Promise<string> => {
    if (typeof pdfjsLib === 'undefined') return "";
    const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
    let fullText = "";
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const textContent = await page.getTextContent();
      const pageText = textContent.items.map((item: any) => item.str).join(" ");
      fullText += pageText + "\n\n";
    }
    return fullText;
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, isLesson: boolean) => {
    const file = e.target.files?.[0];
    if (file) processFile(file, isLesson);
    e.target.value = '';
  };

  // Component hiển thị ô upload
  const UploadBox = ({ 
    title, 
    subTitle, 
    inputRef, 
    fileName, 
    isProcessing, 
    isLesson,
    hasContent
  }: { 
    title: string, 
    subTitle: string, 
    inputRef: React.RefObject<HTMLInputElement | null>, 
    fileName: string | null, 
    isProcessing: boolean, 
    isLesson: boolean,
    hasContent: boolean
  }) => (
    <div 
      onClick={() => inputRef.current?.click()}
      className={`group relative overflow-hidden rounded-2xl border-2 border-dashed p-8 transition-all duration-300 cursor-pointer text-center
        ${hasContent 
            ? 'border-emerald-300 bg-emerald-50/50 hover:bg-emerald-50' 
            : 'border-slate-300 bg-slate-50 hover:border-indigo-400 hover:bg-indigo-50/30'
        }
      `}
    >
      <input 
        type="file" 
        ref={inputRef}
        onChange={(e) => handleFileChange(e, isLesson)}
        accept=".pdf,.docx" 
        className="hidden" 
      />

      <div className="flex flex-col items-center justify-center relative z-10">
        {isProcessing ? (
           <div className="p-4 bg-white rounded-full shadow-lg mb-3">
               <Loader2 className="text-indigo-600 animate-spin" size={32} />
           </div>
        ) : hasContent ? (
           <div className="p-4 bg-white rounded-full shadow-lg shadow-emerald-200 mb-3">
             <CheckCircle2 className="text-emerald-500" size={32} />
           </div>
        ) : (
          <div className={`p-4 rounded-full shadow-lg mb-4 transition-transform group-hover:-translate-y-1
              ${isLesson ? 'bg-indigo-600 text-white shadow-indigo-200' : 'bg-white text-slate-400 border border-slate-100'}`}
          >
             {isLesson ? <FileText size={28} /> : <FileBarChart size={28} />}
          </div>
        )}

        {isProcessing ? (
             <p className="text-sm font-semibold text-slate-600 animate-pulse">Đang phân tích...</p>
        ) : hasContent ? (
            <>
                <p className="text-sm font-bold text-emerald-800 break-all px-2 line-clamp-1">{fileName}</p>
                <p className="text-xs font-medium text-emerald-600 mt-1 bg-emerald-100 px-3 py-1 rounded-full">Đã sẵn sàng</p>
            </>
        ) : (
            <>
                <p className="text-base font-bold text-slate-700">{title}</p>
                <p className="text-xs text-slate-500 mt-2 max-w-[200px] mx-auto leading-relaxed">{subTitle}</p>
                <div className="mt-4 flex items-center justify-center space-x-2 text-xs text-indigo-500 font-medium opacity-0 group-hover:opacity-100 transition-opacity">
                    <Upload size={12} />
                    <span>Bấm để chọn file</span>
                </div>
            </>
        )}
      </div>
    </div>
  );

  return (
    <div className="bg-white rounded-3xl shadow-xl shadow-indigo-100/50 p-8 border border-white/50 backdrop-blur-sm mt-6">
      <div className="flex items-center mb-6">
        <div className="p-2 bg-indigo-50 rounded-lg mr-3">
            <Upload size={20} className="text-indigo-600"/>
        </div>
        <h2 className="text-xl font-bold text-slate-800">Tài liệu đầu vào</h2>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Ô Upload Giáo án */}
        <div className="flex flex-col h-full">
            <UploadBox 
                title="Tải lên Giáo án" 
                subTitle="Hỗ trợ file Word (.docx) hoặc PDF. Bản đẹp, không phải bản scan." 
                inputRef={lessonInputRef}
                fileName={lessonFileName}
                isProcessing={processingLesson}
                isLesson={true}
                hasContent={!!lessonContent}
            />
             {!lessonContent && (
                <div className="flex items-center justify-center mt-3 text-rose-500 text-xs font-medium">
                    <AlertTriangle size={12} className="mr-1.5"/>
                    <span>Yêu cầu bắt buộc</span>
                </div>
            )}
        </div>

        {/* Ô Upload PPCT */}
        <div className="flex flex-col h-full">
            <UploadBox 
                title="Tải lên PPCT" 
                subTitle="Dùng để trích xuất chính xác năng lực theo quy định nhà trường." 
                inputRef={distInputRef}
                fileName={distFileName}
                isProcessing={processingDist}
                isLesson={false}
                hasContent={!!distributionContent}
            />
        </div>
      </div>
    </div>
  );
};

export default ContentInput;

import React, { useState } from 'react';
import { Download, CheckCircle, FileText, ChevronDown, ChevronUp, Sparkles } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import rehypeRaw from 'rehype-raw';
import { 
  Document, 
  Paragraph, 
  TextRun, 
  HeadingLevel, 
  Packer, 
  UnderlineType, 
  Table, 
  TableRow, 
  TableCell, 
  BorderStyle,
  WidthType,
  AlignmentType
} from 'docx';
import FileSaver from 'file-saver';

interface ResultDisplayProps {
  result: string | null;
  loading: boolean;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ result, loading }) => {
  const [showPreview, setShowPreview] = useState(false);
  const [isGeneratingDoc, setIsGeneratingDoc] = useState(false);

  // Helper: Tạo đối tượng Table cho docx từ mảng string Markdown table
  const createTableFromMarkdown = (tableLines: string[]): Table | null => {
    try {
        const validLines = tableLines.filter(line => !line.match(/^\|?\s*[-:]+[-|\s:]*\|?\s*$/));

        const rows = validLines.map(line => {
            const cells = line.split('|');
            if (line.trim().startsWith('|')) cells.shift();
            if (line.trim().endsWith('|')) cells.pop();

            return new TableRow({
                children: cells.map(cellContent => new TableCell({
                    children: [new Paragraph({
                        children: parseTextWithFormatting(cellContent.trim())
                    })],
                    borders: {
                        top: { style: BorderStyle.SINGLE, size: 1, color: "000000" },
                        bottom: { style: BorderStyle.SINGLE, size: 1, color: "000000" },
                        left: { style: BorderStyle.SINGLE, size: 1, color: "000000" },
                        right: { style: BorderStyle.SINGLE, size: 1, color: "000000" },
                    },
                    width: {
                        size: 100 / cells.length,
                        type: WidthType.PERCENTAGE,
                    }
                }))
            });
        });

        return new Table({
            rows: rows,
            width: {
                size: 100,
                type: WidthType.PERCENTAGE,
            }
        });
    } catch (e) {
        console.error("Lỗi parse table:", e);
        return null;
    }
  };

  const parseTextWithFormatting = (text: string): TextRun[] => {
    const parts = text.split(/(\*\*.*?\*\*|\*.*?\*|<u>.*?<\/u>)/g);

    return parts.map(part => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return new TextRun({
          text: part.slice(2, -2),
          bold: true
        });
      }
      if (part.startsWith('*') && part.endsWith('*') && part.length > 2) {
        return new TextRun({
          text: part.slice(1, -1),
          italics: true
        });
      }
       if (part.startsWith('_') && part.endsWith('_')) {
        return new TextRun({
          text: part.slice(1, -1),
          italics: true
        });
      }
      if (part.startsWith('<u>') && part.endsWith('</u>')) {
          const cleanText = part.replace(/<u>/g, '').replace(/<\/u>/g, '');
          return new TextRun({
              text: cleanText,
              underline: {
                  type: UnderlineType.SINGLE,
              }
          });
      }
      return new TextRun({ text: part });
    });
  };

  const generateDocx = async () => {
    if (!result) return;
    setIsGeneratingDoc(true);

    try {
      const lines = result.split('\n');
      const children: (Paragraph | Table)[] = [];
      let tableBuffer: string[] = [];
      let inTable = false;

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trimEnd();
        const trimmed = line.trim();

        if (trimmed.startsWith('|')) {
            inTable = true;
            tableBuffer.push(line);
            continue;
        } else if (inTable) {
            if (tableBuffer.length > 0) {
                const tableNode = createTableFromMarkdown(tableBuffer);
                if (tableNode) {
                    children.push(tableNode);
                    children.push(new Paragraph({ text: "" }));
                }
                tableBuffer = [];
            }
            inTable = false;
        }

        if (!trimmed) {
          children.push(new Paragraph({ text: "" }));
          continue;
        }

        if (trimmed.startsWith('## ')) {
          children.push(new Paragraph({
            children: parseTextWithFormatting(trimmed.replace('## ', '')),
            heading: HeadingLevel.HEADING_1,
            spacing: { before: 200, after: 100 }
          }));
        } 
        else if (trimmed.startsWith('### ')) {
          children.push(new Paragraph({
             children: parseTextWithFormatting(trimmed.replace('### ', '')),
            heading: HeadingLevel.HEADING_2,
            spacing: { before: 150, after: 50 }
          }));
        }
        else if (trimmed.startsWith('#### ')) {
            children.push(new Paragraph({
               children: parseTextWithFormatting(trimmed.replace('#### ', '')),
              heading: HeadingLevel.HEADING_3,
              spacing: { before: 100, after: 50 }
            }));
        }
        else if (trimmed.startsWith('- ') || trimmed.startsWith('+ ') || trimmed.startsWith('* ')) {
            const content = trimmed.substring(2);
            children.push(new Paragraph({
                children: parseTextWithFormatting(content),
                bullet: { level: 0 }
            }));
        }
        else {
             children.push(new Paragraph({
                children: parseTextWithFormatting(trimmed),
                spacing: { after: 100 },
                alignment: AlignmentType.JUSTIFIED
            }));
        }
      }

      if (tableBuffer.length > 0) {
         const tableNode = createTableFromMarkdown(tableBuffer);
         if (tableNode) children.push(tableNode);
      }

      const doc = new Document({
        sections: [{
          properties: {},
          children: children,
        }],
      });

      const blob = await Packer.toBlob(doc);
      FileSaver.saveAs(blob, "Giao_an_NLS.docx");
    } catch (error) {
      console.error("Lỗi tạo file docx:", error);
      alert("Không thể tạo file .docx chuẩn (Lỗi parser). Hệ thống sẽ tải về file văn bản thô.");
      handleDownloadTxt();
    } finally {
      setIsGeneratingDoc(false);
    }
  };

  const handleDownloadTxt = () => {
    if (!result) return;
    const blob = new Blob([result], { type: 'text/plain' });
    FileSaver.saveAs(blob, 'Giao_an_NLS.txt');
  };

  if (loading) {
    return (
      <div className="bg-white/90 backdrop-blur-md p-16 rounded-3xl shadow-xl border border-indigo-100 flex flex-col items-center justify-center min-h-[400px]">
        <div className="relative">
             <div className="absolute inset-0 bg-indigo-500 rounded-full blur-xl opacity-20 animate-pulse"></div>
             <div className="relative p-6 bg-white rounded-full shadow-lg">
                <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-100 border-t-indigo-600"></div>
             </div>
        </div>
        <h3 className="text-xl font-bold text-slate-800 mt-8">Đang tích hợp Năng Lực Số</h3>
        <p className="text-slate-500 mt-2 text-center max-w-xs">Hệ thống đang phân tích ngữ nghĩa và đối chiếu quy định...</p>
      </div>
    );
  }

  if (!result) return null;

  return (
    <div className="bg-white rounded-3xl shadow-2xl shadow-indigo-200/50 border border-indigo-50 overflow-hidden animate-fade-in-up">
      <div className="relative bg-gradient-to-br from-indigo-600 via-purple-600 to-indigo-800 px-6 py-12 flex flex-col items-center justify-center text-center space-y-4 text-white overflow-hidden">
        {/* Background Patterns */}
        <div className="absolute top-0 left-0 w-full h-full opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-purple-400 rounded-full blur-3xl opacity-30"></div>

        <div className="relative z-10 p-3 bg-white/10 backdrop-blur-md rounded-full border border-white/20">
           <Sparkles className="text-yellow-300" size={32} />
        </div>

        <div className="relative z-10">
            <h2 className="text-3xl font-extrabold tracking-tight">Hoàn tất xử lý!</h2>
            <p className="text-indigo-100 mt-2 max-w-lg mx-auto text-lg font-light">
                Giáo án của bạn đã được nâng cấp với các năng lực số phù hợp nhất.
            </p>
            {result.includes("(Nội dung trích xuất nguyên văn từ PPCT)") && (
                 <div className="mt-4 inline-flex items-center px-4 py-1.5 rounded-full bg-emerald-500/20 border border-emerald-400/30 text-emerald-100 text-sm font-medium">
                    <CheckCircle size={14} className="mr-2" />
                    Tuân thủ chính xác PPCT
                 </div>
            )}
        </div>

        <div className="flex flex-col sm:flex-row gap-4 mt-8 w-full max-w-md relative z-10">
          <button 
            onClick={generateDocx}
            disabled={isGeneratingDoc}
            className="flex-1 flex items-center justify-center space-x-2 px-6 py-4 bg-white text-indigo-700 rounded-2xl text-lg font-bold hover:bg-indigo-50 transition-all shadow-lg transform hover:-translate-y-1 active:scale-95"
          >
             {isGeneratingDoc ? (
                 <span className="animate-pulse">Đang tạo file...</span>
             ) : (
                 <>
                    <Download size={22} />
                    <span>Tải về DOCX</span>
                 </>
             )}
          </button>
           <button 
            onClick={handleDownloadTxt}
            className="flex-none flex items-center justify-center px-5 py-4 bg-indigo-800/50 backdrop-blur-sm text-white rounded-2xl font-medium border border-indigo-500/30 hover:bg-indigo-700/50 transition-colors"
            title="Tải bản text dự phòng"
           >
             <FileText size={22} />
          </button>
        </div>
      </div>

      <div className="bg-slate-50 border-t border-slate-200">
        <button 
            onClick={() => setShowPreview(!showPreview)}
            className="w-full flex items-center justify-center text-slate-500 text-sm font-semibold uppercase tracking-wider py-4 hover:bg-slate-100 transition-colors"
        >
            {showPreview ? (
                <>Thu gọn <ChevronUp size={16} className="ml-2" /></>
            ) : (
                <>Xem trước nội dung <ChevronDown size={16} className="ml-2" /></>
            )}
        </button>
      </div>

      {showPreview && (
        <div className="p-10 prose prose-slate max-w-none prose-p:text-slate-600 prose-headings:text-indigo-900 prose-headings:font-bold prose-strong:text-indigo-700 prose-li:text-slate-600 border-t border-slate-200 bg-white">
            <ReactMarkdown rehypePlugins={[rehypeRaw]}>
            {result}
            </ReactMarkdown>
        </div>
      )}
    </div>
  );
};

