import React, { useState } from 'react';
import { Download, CheckCircle, FileText, ChevronDown, ChevronUp, Sparkles } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import rehypeRaw from 'rehype-raw';
import { 
  Document, 
  Paragraph, 
  TextRun, 
  HeadingLevel, 
  Packer, 
  UnderlineType, 
  Table, 
  TableRow, 
  TableCell, 
  BorderStyle,
  WidthType,
  AlignmentType
} from 'docx';
import FileSaver from 'file-saver';

interface ResultDisplayProps {
  result: string | null;
  loading: boolean;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ result, loading }) => {
  const [showPreview, setShowPreview] = useState(false);
  const [isGeneratingDoc, setIsGeneratingDoc] = useState(false);

  // Helper: Parse text with bold, italic, underline, and line breaks (<br>)
  const parseTextWithFormatting = (text: string): TextRun[] => {
    const runs: TextRun[] = [];

    // Regex to capture formatting blocks. 
    // Added _italic_ support and [\s\S] for multi-line safety.
    const regex = /(\*\*[\s\S]*?\*\*|\*[\s\S]*?\*|_[\s\S]*?_|<u>[\s\S]*?<\/u>)/g;

    const parts = text.split(regex);

    // Helper to process a text segment: handles <br> tags by inserting breaks
    const processSegment = (content: string, styles: { bold?: boolean, italics?: boolean, underline?: boolean }) => {
        // Split by <br>, <br/>, <br /> (case insensitive)
        const segments = content.split(/<br\s*\/?>/gi);

        segments.forEach((seg, index) => {
            // If this is not the first segment, it means we hit a <br>, so add a break
            if (index > 0) {
                runs.push(new TextRun({ text: "", break: 1 }));
            }

            if (seg) {
                runs.push(new TextRun({
                    text: seg,
                    bold: styles.bold,
                    italics: styles.italics,
                    underline: styles.underline ? { type: UnderlineType.SINGLE } : undefined,
                    font: "Times New Roman",
                    size: 28, // 14pt (redundant if default is set, but ensures consistency)
                }));
            }
        });
    };

    parts.forEach(part => {
        if (!part) return;

        if (part.startsWith('**') && part.endsWith('**')) {
            processSegment(part.slice(2, -2), { bold: true });
        } else if (part.startsWith('*') && part.endsWith('*') && part.length > 2) {
             processSegment(part.slice(1, -1), { italics: true });
        } else if (part.startsWith('_') && part.endsWith('_') && part.length > 2) {
             processSegment(part.slice(1, -1), { italics: true });
        } else if (part.startsWith('<u>') && part.endsWith('</u>')) {
            // Remove start and end tags
            const clean = part.replace(/^<u>|<\/u>$/g, '');
            processSegment(clean, { underline: true });
        } else {
            // Plain text
            processSegment(part, {});
        }
    });

    return runs;
  };

  // Helper: Tạo đối tượng Table cho docx từ mảng string Markdown table
  const createTableFromMarkdown = (tableLines: string[]): Table | null => {
    try {
        const validLines = tableLines.filter(line => !line.match(/^\|?\s*[-:]+[-|\s:]*\|?\s*$/));

        const rows = validLines.map(line => {
            const cells = line.split('|');
            // Remove first/last empty elements if pipe is present at boundaries
            if (line.trim().startsWith('|') && cells.length > 0 && cells[0].trim() === '') cells.shift();
            if (line.trim().endsWith('|') && cells.length > 0 && cells[cells.length - 1].trim() === '') cells.pop();

            return new TableRow({
                children: cells.map(cellContent => {
                    return new TableCell({
                        children: [new Paragraph({
                            children: parseTextWithFormatting(cellContent.trim()),
                            spacing: { line: 240, lineRule: "auto" } // Single spacing
                        })],
                        borders: {
                            top: { style: BorderStyle.SINGLE, size: 1, color: "000000" },
                            bottom: { style: BorderStyle.SINGLE, size: 1, color: "000000" },
                            left: { style: BorderStyle.SINGLE, size: 1, color: "000000" },
                            right: { style: BorderStyle.SINGLE, size: 1, color: "000000" },
                        },
                        width: {
                            size: 100 / Math.max(cells.length, 1),
                            type: WidthType.PERCENTAGE,
                        }
                    })
                })
            });
        });

        return new Table({
            rows: rows,
            width: {
                size: 100,
                type: WidthType.PERCENTAGE,
            }
        });
    } catch (e) {
        console.error("Lỗi parse table:", e);
        return null;
    }
  };

  const generateDocx = async () => {
    if (!result) return;
    setIsGeneratingDoc(true);

    try {
      const lines = result.split('\n');
      const children: (Paragraph | Table)[] = [];
      let tableBuffer: string[] = [];
      let inTable = false;

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trimEnd();
        const trimmed = line.trim();

        if (trimmed.startsWith('|')) {
            inTable = true;
            tableBuffer.push(line);
            continue;
        } else if (inTable) {
            if (tableBuffer.length > 0) {
                const tableNode = createTableFromMarkdown(tableBuffer);
                if (tableNode) {
                    children.push(tableNode);
                    children.push(new Paragraph({ text: "" }));
                }
                tableBuffer = [];
            }
            inTable = false;
        }

        if (!trimmed) {
          children.push(new Paragraph({ text: "" }));
          continue;
        }

        // Heading formatting adjustments for 14pt document base
        if (trimmed.startsWith('## ')) {
          children.push(new Paragraph({
            children: parseTextWithFormatting(trimmed.replace('## ', '')),
            heading: HeadingLevel.HEADING_1,
            spacing: { before: 240, after: 120 }
          }));
        } 
        else if (trimmed.startsWith('### ')) {
          children.push(new Paragraph({
             children: parseTextWithFormatting(trimmed.replace('### ', '')),
            heading: HeadingLevel.HEADING_2,
            spacing: { before: 240, after: 120 }
          }));
        }
        else if (trimmed.startsWith('#### ')) {
            children.push(new Paragraph({
               children: parseTextWithFormatting(trimmed.replace('#### ', '')),
              heading: HeadingLevel.HEADING_3,
              spacing: { before: 240, after: 120 }
            }));
        }
        else if (trimmed.startsWith('- ') || trimmed.startsWith('+ ') || trimmed.startsWith('* ')) {
            const content = trimmed.substring(2);
            children.push(new Paragraph({
                children: parseTextWithFormatting(content),
                bullet: { level: 0 },
                spacing: { after: 120, line: 240, lineRule: "auto" }
            }));
        }
        else {
             children.push(new Paragraph({
                children: parseTextWithFormatting(trimmed),
                spacing: { after: 120, line: 240, lineRule: "auto" },
                alignment: AlignmentType.JUSTIFIED
            }));
        }
      }

      // Handle any pending table at the end of the file
      if (tableBuffer.length > 0) {
         const tableNode = createTableFromMarkdown(tableBuffer);
         if (tableNode) children.push(tableNode);
      }

      // Constants for margins (TWIPs)
      // 1cm ≈ 567 TWIPs
      const marginTop = 1134;    // 2cm
      const marginBottom = 1134; // 2cm
      const marginLeft = 1701;   // 3cm
      const marginRight = 851;   // 1.5cm

      const doc = new Document({
        styles: {
          default: {
            document: {
              run: {
                size: 28, // 14pt (28 half-points)
                font: "Times New Roman",
                color: "000000"
              },
              paragraph: {
                spacing: {
                  line: 240, // Single spacing (240 = 1 line)
                  lineRule: "auto",
                }
              }
            },
            heading1: {
                run: { size: 28, bold: true, font: "Times New Roman", color: "000000" },
                paragraph: { spacing: { before: 240, after: 120 } }
            },
            heading2: {
                run: { size: 28, bold: true, font: "Times New Roman", color: "000000" },
                paragraph: { spacing: { before: 240, after: 120 } }
            },
            heading3: {
                run: { size: 28, bold: true, font: "Times New Roman", color: "000000" },
                paragraph: { spacing: { before: 240, after: 120 } }
            }
          }
        },
        sections: [{
          properties: {
            page: {
              margin: {
                top: marginTop,
                bottom: marginBottom,
                left: marginLeft,
                right: marginRight,
              },
            },
          },
          children: children,
        }],
      });

      const blob = await Packer.toBlob(doc);
      FileSaver.saveAs(blob, "Giao_an_NLS.docx");
    } catch (error) {
      console.error("Lỗi tạo file docx:", error);
      alert("Không thể tạo file .docx chuẩn (Lỗi parser). Hệ thống sẽ tải về file văn bản thô.");
      handleDownloadTxt();
    } finally {
      setIsGeneratingDoc(false);
    }
  };

  const handleDownloadTxt = () => {
    if (!result) return;
    const blob = new Blob([result], { type: 'text/plain' });
    FileSaver.saveAs(blob, 'Giao_an_NLS.txt');
  };

  if (loading) {
    return (
      <div className="bg-white/90 backdrop-blur-md p-16 rounded-3xl shadow-xl border border-indigo-100 flex flex-col items-center justify-center min-h-[400px]">
        <div className="relative">
             <div className="absolute inset-0 bg-indigo-500 rounded-full blur-xl opacity-20 animate-pulse"></div>
             <div className="relative p-6 bg-white rounded-full shadow-lg">
                <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-100 border-t-indigo-600"></div>
             </div>
        </div>
        <h3 className="text-xl font-bold text-slate-800 mt-8">Đang tích hợp Năng Lực Số</h3>
        <p className="text-slate-500 mt-2 text-center max-w-xs">Hệ thống đang phân tích ngữ nghĩa và đối chiếu quy định...</p>
      </div>
    );
  }

  if (!result) return null;

  return (
    <div className="bg-white rounded-3xl shadow-2xl shadow-indigo-200/50 border border-indigo-50 overflow-hidden animate-fade-in-up">
      <div className="relative bg-gradient-to-br from-indigo-600 via-purple-600 to-indigo-800 px-6 py-12 flex flex-col items-center justify-center text-center space-y-4 text-white overflow-hidden">
        {/* Background Patterns */}
        <div className="absolute top-0 left-0 w-full h-full opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-purple-400 rounded-full blur-3xl opacity-30"></div>

        <div className="relative z-10 p-3 bg-white/10 backdrop-blur-md rounded-full border border-white/20">
           <Sparkles className="text-yellow-300" size={32} />
        </div>

        <div className="relative z-10">
            <h2 className="text-3xl font-extrabold tracking-tight">Hoàn tất xử lý!</h2>
            <p className="text-indigo-100 mt-2 max-w-lg mx-auto text-lg font-light">
                Giáo án của bạn đã được nâng cấp với các năng lực số phù hợp nhất.
            </p>
